  ('Rare_6', 'The Deceiver''s Crest', 'Rare', 'When I level up, create a copy of my champion spell in hand. It costs 0 this round.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0011.png'),
