  ('Rare_9', 'The Gravedigger''s Spade', 'Rare', 'Round Start: Draw 1 and give it Fleeting.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0014.png'),
  ('Rare_10', 'Luden''s Tempest', 'Rare', 'All of your spells and skills deal 1 extra damage.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0017.png'),
  ('Rare_11', 'The Berserker''s Buckle', 'Rare', 'When I survive damage, grant me +2|+2.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0019.png'),
  ('Rare_12', 'The Grand General''s Counterplan', 'Rare', 'Round Start: Create a Fleeting copy of me in hand.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0020.png'),
  ('Rare_13', 'Dreadway Chase Gun', 'Rare', 'When I''m summoned, create 2 Warning Shots in hand.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0021.png'),
  ('Rare_14', 'Laurent Bladerack', 'Rare', 'Allies have Challenger.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0023.png'),
  ('Rare_15', 'Troll King''s Crown', 'Rare', 'Allies have Overwhelm.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0025.png'),
  ('Rare_16', 'Luminous Orb', 'Rare', '+0|+3 and Sharpsight.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0026.png'),
  ('Rare_17', 'The Bounty Hunter''s Renown', 'Rare', 'I have +1|+1 for every 200 gold you have.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0027.png'),
  ('Rare_18', 'The Collector', 'Rare', '+1|+1 and when I kill an enemy, you earn 50 gold. (Max 2 kills per encounter)', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0029.png'),
  ('Rare_19', 'Tempest Blade', 'Rare', 'When I level up, Stun all enemies.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0031.png'),
  ('Rare_20', 'Turret Plating', 'Rare', 'Your Nexus has Tough.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0033.png'),
  ('Rare_21', 'Riptide Battery', 'Rare', 'Plunder: Play a Cannon Barrage a number of times equal to my cost.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0034.png'),
  ('Rare_22', 'The Card Master''s Gambit', 'Rare', '+1|+1 and when you win an encounter without taking any Nexus damage, earn 1 Reroll.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0035.png'),
  ('Rare_23', 'The Loose Cannon''s Payload', 'Rare', 'When I''m summoned, discard your hand then create that many Pow-Pows in hand.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0036.png'),
  ('Rare_24', 'Hymn of Valor', 'Rare', 'When I''m summoned, create a Redoubled Valor in hand. It costs 3.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0037.png'),
  ('Rare_25', 'The Curator''s Gatebreaker', 'Rare', 'When I''m summoned, I strike the enemy Nexus.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0038.png'),
  ('Rare_26', 'Stalker''s Blade', 'Rare', 'When I''m summoned, I strike the weakest enemy.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0040.png'),
  ('Rare_27', 'Greenglade Shadeleaf', 'Rare', 'Support: Grant my supported ally Elusive.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0041.png'),
  ('Rare_28', 'Star Gem', 'Rare', 'Allied champions have +1|+1 and cost 2 less.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0043.png'),
  ('Rare_29', 'Guardian''s Trinket', 'Rare', 'Adventure Start: Add 2 copied of a random Champion to your deck. Attach a random Epic item to it.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0044.png'),
  ('Rare_30', 'Chemtech Duplicator', 'Rare', 'When you play a spell, if you have 6+ mana gems, copy it with the same targets.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0048.png'),
  ('Rare_31', 'Condenser', 'Rare', 'Support: Create a 1 cost 1|1 copy of my supported ally in hand.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0075.png'),
  ('Rare_32', 'Corrupted Star Fragment', 'Rare', 'Support: Kill my supported ally and grant me its keywords and stats.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0045.png'),
  ('Rare_33', 'Galeforce', 'Rare', 'Scout Round End: Shuffle me into your deck.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0050.png'),
  ('Rare_34', 'Golden Spatula', 'Rare', 'When i''m summoned, grant me +1|+1 and a random keyword for every 30 cards that started in your deck.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0051.png'),
  ('Rare_35', 'Guardian''s Orb', 'Rare', 'When i''m summoned, grant Epic items to 3 randoÃ¹ cards in your deck.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0052.png'),
  ('Rare_36', 'Succubus''s Brand', 'Rare', '+1|+1 and when i kill a unit, summon a random husk.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0053.png'),
  ('Rare_37', 'Transmogulator', 'Rare', 'Support: Transform my supported ally into a random follower that costs 3 more.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0081.png'),
  ('Rare_38', 'Utmost Despair', 'Rare', 'Play: Grant enemies Gloom.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0095.png'),
  ('Rare_39', 'Voidborne Carapace', 'Rare', 'Evolve When ANY unit dies, grant me its keywords.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0049.png'),
