  ('Rare_41', 'Wriggle''s Lantern', 'Rare', 'Round end: Grant me Impact twice if I''m in hand (max Impact 10).', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0054.png'),
  ('Rare_42', 'Arcane Comet', 'Rare', 'Round Start: Create a Fleeting Falling Comet in hand..', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0046.png'),
  ('Rare_43', 'Spirit Forge (Consumable)', 'Rare', 'Quest: Win a 3+ Stard Adventure. Reward: Upgrade a Rare Reli Slot on this champion to Epic.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0069.png');
INSERT INTO relics_epic (relic_id, relic_name, relic_rarity, relic_description, relic_icon) VALUES
  ('Epic_1', 'Chosen by the Stars', 'Epic', 'Fated, AugmentEmpowered 10: Overwhelm, Regeneration, and Challenger.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0058.png'),
  ('Epic_2', 'Death''s Foil', 'Epic', '+1|+0While I''m attacking, I can''t take damage or die.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0059.png'),
  ('Epic_3', 'Disciple of Shadows', 'Epic', 'I cost 1 less for each ally in play.Play: Deal 3 to all other allies.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0060.png'),
  ('Epic_4', 'Echoing Spirit', 'Epic', 'Game Start: Create 7 copies of me in deck. Champion Spells cost 1 less.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0061.png'),
  ('Epic_5', 'Found Fortune', 'Epic', 'Play: Draw the highest cost card that costs less than my base cost, grant it an Epic item, and reduce its cost to 0.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0062.png'),
  ('Epic_6', 'Oath of the Guardians', 'Epic', 'Play: Shuffle 5 level 2 champions into your deck and double their stats, then draw one of them.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0064.png'),
  ('Epic_7', 'Packed Powder', 'Epic', 'Plunder: I cost 2 less.I have +1|+1 for each different round you''ve damaged the enemy Nexus.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0065.png'),
  ('Epic_8', 'Portal Pals', 'Epic', 'When I''m summoned, create 2 random 7+ cost units from your regions and reduce their cost by my base cost.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0066.png'),
  ('Epic_9', 'Spirit of the Buhru', 'Epic', 'Power: Allies that cost 1 or less have Overwhelm, Quick Attack, and Fury.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0079.png'),
  ('Epic_10', 'The Beast Within', 'Epic', 'Power: Allies have Overwhelm, and if they have a subtype, +1|+1.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0080.png'),
  ('Epic_11', 'Starforged Gauntlets', 'Epic', 'Power: Game Start: If I''m in deck or hand and Titanic, +1 Starting Mana. You can find Level 2 Champions when you Invoke or Manifest.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0082.png'),
  ('Epic_12', 'Secret Technique', 'Epic', 'Power: When an ally gains stats from a spell, it gains twice that many instead.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0085.png'),
  ('Epic_13', 'Spellweaver''s Symphony', 'Epic', 'Power: When you gain the attack token, create a random spell that costs 2 from your regions in hand. It costs 0 and is Fleeting.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0086.png'),
  ('Epic_14', 'Full Build', 'Epic', 'Challenger, Tough, and Overwhelm', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0089.png'),
  ('Epic_15', 'Strength of Stone', 'Epic', '+0|+2Power: When you summon an ally, grant it +0|+1 and Formidable', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0091.png'),
  ('Epic_16', 'Spectral Scissors', 'Epic', '+2|+0Support: If my supported ally is a follower, grant it Ephemeral and summon an exact copy of it attacking.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0092.png'),
  ('Epic_17', 'Norra''s Portal Accelerator', 'Epic', 'Power: Game Start: If I''m Norra, +1 starting mana.When you summon a created ally, grant it Impact.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0094.png'),
  ('Epic_18', 'Fear-Cleaving Axe', 'Epic', 'Spirit Attack: Boost all units.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0097.png'),
  ('Epic_19', 'Lux''s Incandescent Baton', 'Epic', 'Power: If I''m Lux, +1 starting mana.Game Start: Draw a follower that costs 2 or less and grant it Targon''s Brace.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0098.png'),
  ('Epic_20', 'Icon of Valhir', 'Epic', 'Power: Your elemental spells and Skills deal 2 extra damage.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0099.png'),
  ('Epic_21', 'Shock & Awe', 'Epic', 'Power: When an ally that costs 1 or less attacks,  deal 1 to the enemy Nexus.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0100.png'),
  ('Epic_22', 'Yasuo''s Windblade', 'Epic', 'Power: If I''m Yasuo, +1 starting mana. When you Recall an enemy, increase its cost by 2.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0103.png'),
  ('Epic_23', 'Swain''s Raven Army', 'Epic', 'Power: Game Start: Drain 5 from the enemy Nexus.Play: If I''m Swain, refill your spell mana.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0104.png'),
  ('Epic_24', 'Jayce''s Hextech Battery', 'Epic', '+1|+2.When I level up, refill 3 mana. If I''m Jayce, refill 6 mana instead.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0105.png'),
  ('Epic_25', 'Deadly Harpoon', 'Epic', '+2|+0 and Challenger.Power: Game Start: Shuffle two Deaths From Below into your deck and grant Deaths From Below a random epic item.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0106.png'),
  ('Epic_26', 'Hextech Rifle', 'Epic', 'Power: Game Start: Plant 6 Flashbomb Traps in the top 8 cards of the enemy deck. When a trap misses, replant it in the top 8 cards of the enemy deck.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0107.png'),
  ('Epic_27', 'Cease and Desist', 'Epic', '3 ImpactPlay: If I have 10+ Power, give me Barrier and start a free attack Challenging the strongest enemy.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0108.png'),
  ('Epic_28', 'Frozen Tomb', 'Epic', 'Game Start: If I''m in deck or hand, summon a Stormcarved Spire with Countdown 4: Summon me.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0109.png'),
  ('Epic_29', 'Big Guns', 'Epic', 'Power: Your spells and skills deal 1 extra damage.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0111.png'),
  ('Epic_30', 'Living Weapon', 'Epic', 'Play, Attack, and Round Start: Forge me.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0112.png'),
  ('Epic_31', 'Hidden Tome', 'Epic', 'Power: When you play or level up a champion, refill your spell mana.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0113.png'),
  ('Epic_32', 'Black Shield', 'Epic', 'Power: When you summon an ally, grant it SpellShield.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0114.png'),
  ('Epic_33', 'Loaded Dice', 'Epic', '+3 Rerolls+10% to find Epic powers and items.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0115.png'),
  ('Epic_34', 'Stacked Deck', 'Epic', '+200 Starting Gold.Power: Allies have +1|+1 for every 12 cards in your deck past 18 at game start.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0116.png'),
  ('Epic_35', 'Siren''s Call', 'Epic', 'Power: Game Start: Create an Evelynn in hand. When you summon a Husk, it loses Immobile.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0117.png'),
  ('Epic_36', 'Defense Spending', 'Epic', 'Power: Your Nexus has Tough. I am Tech.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0118.png'),
  ('Epic_37', 'Essence Theft', 'Epic', 'When you Recall another unit, grant me +1|+0.Power: Game Start: Create a Homecoming in hand and grant it Double Time Watch.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0119.png'),
  ('Epic_38', 'Twin Drakehounds', 'Epic', 'OverwhelmAttack: Deal 2 to the enemy Nexus. If I''ve already attacked this round, deal 2 to all enemies as well.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0120.png'),
  ('Epic_39', 'Harmless Scarecrow', 'Epic', 'Power: When you play a card that costs 3+ mana, Terrify 1. While the enemy deck has 15 or fewer cards, allies have +2|+2 and Overwhelm.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0121.png'),
  ('Epic_40', 'Cruel Experiments', 'Epic', 'Power: When you play an ally with 2+ Health, deal 1 to it and grant it Overwhelm and Impact.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0122.png'),
  ('Epic_41', 'Searing Brilliance', 'Epic', 'Power: Game Start: Grant a random spell from your deck an item with "-1 cost and draw 1". Create 4 copies of it in your deck.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0123.png'),
  ('Epic_42', 'Starfire Spellblade', 'Epic', 'Power: If I''m Kayle, +1 Starting Mana.I have +1|+0 for each encounter you''ve won this adventure.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0124.png'),
  ('Epic_43', 'Perfect Hex Core', 'Epic', 'Power: Round Start: Create a Hex Core Upgrade in hand. Your Hex Core Upgrades have Stopwatch and can upgrade any ally.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0125.png'),
  ('Epic_44', 'Great Talons', 'Epic', 'Power: When you play a 6+ base cost unit, deal 2 to all enemies and the enemy Nexus.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0126.png'),
  ('Epic_45', 'Scales of Judgment', 'Epic', 'Power: When you play a champion, it strikes the weakest enemy. If it''s Nasus, it also strikes the strongest enemy.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0127.png'),
  ('Epic_46', 'Treasures of the Deep', 'Epic', 'Deep and I am a Sea Monster.When I''m summoned, if you aren''t Deep, Toss equal to my cost.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0128.png'),
  ('Epic_47', 'Protectors of Demacia', 'Epic', 'Power: When you level up an allied champion, summon Lux. If you already have Lux, summon Garen instead. If you have both and not Galio, summon Galio.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0130.png'),
  ('Epic_48', 'Warlord''s Helmet', 'Epic', '+10 Nexus Health.Power: If I''m Tryndamere, when you grant stats to a unit in your deck, grant twice as much.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0131.png'),
  ('Epic_49', 'Scoundrel Hunter', 'Epic', 'ChallengerPower: When you play a champion, summon a Warlord''s Palace or advance it 2 rounds.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0132.png'),
  ('Epic_50', 'Shield of Daybreak', 'Epic', 'Power: Allies with Daybreak have Tough. When an ally activates Daybreak, grant allies +0|+1.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0133.png'),
  ('Epic_51', 'Deck of Destiny', 'Epic', '+1|+1Power: Game Start: Create a 1 cost Wild Card in your deck for every 7 cards in your deck.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0134.png'),
  ('Epic_52', 'Champion''s Purse', 'Epic', '+2|+0 and Overwhelm.When I kill an enemy in combat, create 2 Coins in hand.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0135.png'),
  ('Epic_53', 'Mischiefmaker''s Flute', 'Epic', 'SpellshieldWhen I deal damage, plant that many Poison Puffcaps in the enemy deck.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0136.png'),
  ('Epic_54', 'Whisper', 'Epic', 'Power: Your Skills deal 1 extra damage per Stunned enemy.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0137.png'),
  ('Epic_55', 'Siphoned Sorrow', 'Epic', 'When I''m summoned or Round Start: I steal up to 3 Health from a random enemy unit. It can''t drop below 1 health.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0138.png'),
  ('Epic_56', 'Soul Lantern', 'Epic', 'Tough SpellShield Attack: If I''m Thresh, summon an attacking Ephemeral copy of a champion in your deck with less Power.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0139.png'),
  ('Epic_57', 'Attendant Spirits', 'Epic', 'Power: Ephemeral allies have Overwhelm.Play: If I''m a Spirit Blossom unit, Summon 2 Fox-Fires.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0140.png'),
  ('Epic_58', 'The Taker''s Bow', 'Epic', 'Power: Attacking Ephemeral allies can''t take damage or die.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0141.png'),
  ('Epic_59', 'Spirit Glove', 'Epic', 'OverwhelmGame Start: If I''m a Spirit Blossom unit, set my cost to 10.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0142.png'),
  ('Epic_60', 'Frost Breath', 'Epic', 'ToughPlay: Frostbite the strongest enemy. If I''m Anivia, Frostbite ALL enemies instead.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0143.png'),
  ('Epic_61', 'Emotional Support Bear', 'Epic', 'Power: Game Start: Shuffle 3 Tibbers into your deck.Your Tibbers cost 2 less and have +5|+5.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0144.png'),
  ('Epic_62', 'Timehonored Blade', 'Epic', 'If I''m a Spirit Blossom unit, I cost 1 less for each different round you targeted an ally.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0145.png'),
  ('Epic_63', 'The Hand of Noxus', 'Epic', '+2|+0 and Challenger,Play: Play Apprehend on the strongest enemy.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0146.png'),
  ('Epic_64', 'The Darkin Blade', 'Epic', '+0|+3 Power: When you play or transform a Darkin, it strikes the weakest enemy.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0147.png'),
  ('Epic_65', 'Azir''s Staff of Office', 'Epic', '+1|+1If I''m an Ascended, I cost 1 less.Play: Advance your Buried Sun Disc 3 rounds.                ', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0148.png'),
  ('Epic_66', 'Draconic Runes', 'Epic', 'If I''m a Dragon, I have +4|+0 and Overwhelm. Otherwise, I have +2|+0 and Fury.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0149.png'),
  ('Epic_67', 'Queen''s Embrace', 'Epic', 'Spirit, Impact, Evolve.Power: Fearsome allies can only be blocked by units with 5+ Power.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0150.png'),
  ('Epic_68', 'Royal Nibbles', 'Epic', '+1|+1, RegenerationI cost 1 less for each Poro ally in play.', 'https://dd.b.pvp.net/6_12_0/adventure/en_us/img/relics/R0151.png');
